nt}>${escapeHtml(section.label)}</a>`;\n}\n\nfunction escapeHtml(value) {\n  return String(value)\n    .replaceAll(\"&\", \"&amp;\")\n    .replaceAll(\"<\", \"&lt;\")\n    .replaceAll(\">\", \"&gt;\")\n    .replaceAll('\"', \"&quot;\")\n    .replaceAll(\"'\", \"&#39;\");\n}\n","exit_code":0,"status":"completed"}}
