;\\n  }\\n}\\n\\nexport async function writeShoppingProfile(profile, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {\\n  const normalized = normalizeShoppingProfile(profile);\\n  const target = resolve(filePath);\\n  await mkdir(dirname(target), { recursive: true });\\n  await writeFile(target, `${JSON.stringify(normalized, null, 2)}\\\\n`, \\\"utf8\\\");\\n  return normalized;\\n}\\n\\nexport async function updateShoppingProfile(patch, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {\\n  const current = await readShoppingProfile(filePath);\\n  const next = normalizeShoppingProfile({\\n    ...current,\\n    ...patch,\\n    sizes: patch.sizes ? { ...current.sizes, ...patch.sizes } : current.sizes,\\n    budgetAnchors: patch.budgetAnchors\\n      ? { ...current.budgetAnchors, ...patch.budgetAnchors }\\n      : current.budgetAnchors,\\n  });\\n  return writeShoppingProfile(next, filePath);\\n}\\n\\nexport function normalizeShoppingProfile(profile) {\\n  if (!profile || typeof profile !== \\\"object\\\" || Array.isArray(profile)) {\\n    throw new TypeError(\\\"Shopping profile must be an object.\\\");\\n  }\\n\\n  const country = normalizeCode(profile.country, \\\"country\\\", 2);\\n  const currency = normalizeCode(profile.currency, \\\"currency\\\", 3);\\n  const perItemPriceCeiling = normalizeMoney(\\n    profile.perItemPriceCeiling,\\n    \\\"perItemPriceCeiling\\\",\\n    currency,\\n  );\\n\\n  return {\\n    schemaVersion: SHOPPING_PROFILE_SCHEMA_VERSION,\\n    country,\\n    currency,\\n    sizes: normalizeRecord(profile.sizes, \\\"sizes\\\", normalizeSize),\\n    budgetAnchors: normalizeRecord(profile.budgetAnchors, \\\"budgetAnchors\\\", (value, key) =>\\n      normalizeBudgetAnchor(value, key, currency),\\n    ),\\n    hardExclusions: normalizeUniqueStringArray(profile.hardExclusions, \\\"hardExclusions\\\"),\\n    perItemPriceCeiling,\\n    enabledRetailers: normalizeUniqueStringArray(profile.enabledRetailers, \\\"enabledRetailers\\\"),\\n  };\\n}\\n\\nfunction normalizeCode(value, field, length) {\\n  if (typeof value !== \\\"string\\\") {\\n    throw new TypeError(`${field} must be a string.`);\\n  }\\n  const normalized = value.trim().toUpperCase();\\n  if (!new RegExp(`^[A-Z]{${length}}$`).test(normalized)) {\\n    throw new TypeError(`${field} must be a ${length}-letter uppercase code.`);\\n  }\\n  return normalized;\\n}\\n\\nfunction normalizeRecord(value, field, normalizeValue) {\\n  if (!value || typeof value !== \\\"object\\\" || Array.isArray(value)) {\\n    throw new TypeError(`${field} must be an object.`);\\n  }\\n\\n  return Object.fromEntries(\\n    Object.entries(value).map(([key, item]) => {\\n      const normalizedKey = String(key).trim();\\n      if (!normalizedKey) {\\n        throw new TypeError(`${field} keys must be non-empty strings.`);\\n      }\\n      return [normalizedKey, normalizeValue(item, normalizedKey)];\\n    }),\\n  );\\n}\\n\\nfunction normalizeSize(value, key) {\\n  if (!value || typeof value !== \\\"object\\\" || Array.isArray(value)) {\\n    throw new TypeError(`sizes.${key} must be an object.`);\\n  }\\n  if (typeof value.value !== \\\"string\\\" || !value.value.trim()) {\\n    throw new TypeError(`sizes.${key}.value must be a non-empty string.`);\\n  }\\n\\n  const normalized = { value: value.value.trim() };\\n  if (value.system !== undefined) {\\n    if (typeof value.system !== \\\"string\\\" || !value.system.trim()) {\\n      throw new TypeError(`sizes.${key}.system must be a non-empty string.`);\\n    }\\n    normalized.system = value.system.trim();\\n  }\\n  if (value.notes !== undefined) {\\n    if (typeof value.notes !== \\\"string\\\") {\\n      throw new TypeError(`sizes.${key}.notes must be a string.`);\\n    }\\n    normalized.notes = value.notes.trim();\\n  }\\n  return normalized;\\n}\\n\\nfunction normalizeMoney(value, field, defaultCurrency) {\\n  if (!value || typeof value !== \\\"object\\\" || Array.isArray(value)) {\\n    throw new TypeError(`${field} must be an object.`);\\n  }\\n  if (typeof value.amount !== \\\"number\\\" || !Number.isFinite(value.amount) || value.amount < 0) {\\n    throw new TypeError(`${field}.amount must be a non-negative finite number.`);\\n  }\\n\\n  return {\\n    amount: value.amount,\\n    currency:\\n      value.currency === undefined\\n        ? defaultCurrency\\n        : normalizeCode(value.currency, `${field}.currency`, 3),\\n  };\\n}\\n\\nfunction normalizeBudgetAnchor(value, key, defaultCurrency) {\\n  const field = `budgetAnchors.${key}`;\\n  const normalized = normalizeMoney(value, field, defaultCurrency);\\n\\n  if (value.cadence !== undefined) {\\n    if (![\\\"per_item\\\", \\\"monthly\\\", \\\"seasonal\\\", \\\"annual\\\"].includes(value.cadence)) {\\n      throw new TypeError(`${field}.cadence must be per_item, monthly, seasonal, or annual.`);\\n    }\\n    normalized.cadence = value.cadence;\\n  }\\n  if (value.notes !== undefined) {\\n    if (typeof value.notes !== \\\"string\\\") {\\n      throw new TypeError(`${field}.notes must be a string.`);\\n    }\\n    normalized.notes = value.notes.trim();\\n  }\\n\\n  return normalized;\\n}\\n\\nfunction normalizeUniqueStringArray(value, field) {\\n  if (!Array.isArray(value)) {\\n    throw new TypeError(`${field} must be an array.`);\\n  }\\n\\n  return [...new Set(value.map((item) => {\\n    if (typeof item !== \\\"string\\\" || !item.trim()) {\\n      throw new TypeError(`${field} entries must be non-empty strings.`);\\n    }\\n    return item.trim();\\n  }))];\\n}\\n\",\"exit_code\":0,\"status\":\"completed\"}}\nspec/KAN-6/runs/20260509T134122Z-25602553083/execution.json:20:{\"type\":\"item.started\",\"item\":{\"id\":\"item_10\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,280p' test/shopping-profile.test.mjs\\\"\",\"aggregated_output\":\"\",\"exit_code\":null,\"status\":\"in_progress\"}}\nspec/KAN-6/runs/20260509T134122Z-25602553083/execution.json:21:{\"type\":\"item.completed\",\"item\":{\"id\":\"item_10\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,280p' test/shopping-profile.test.mjs\\\"\",\"aggregated_output\":\"import { mkdtemp, rm } from \\\"node:fs/promises\\\";\\nimport { join } from \\\"node:path\\\";\\nimport { tmpdir } from \\\"node:os\\\";\\nimport test from \\\"node:test\\\";\\nimport assert from \\\"node:assert/strict\\\";\\n\\nimport {\\n  createDefaultShoppingProfile,\\n  readShoppingProfile,\\n  updateShoppingProfile,\\n  writeShoppingProfile,\\n} from \\\"../src/shopping-profile.mjs\\\";\\n\\ntest(\\\"creates a complete profile shape with required hard constraints\\\", () => {\\n  const profile = createDefaultShoppingProfile({\\n    country: \\\"lv\\\",\\n    currency: \\\"eur\\\",\\n    sizes: {\\n      tops: { value: \\\"M\\\", system: \\\"International\\\" },\\n      shoes: { value: \\\"42\\\", system: \\\"EU\\\" },\\n    },\\n    budgetAnchors: {\\n      jeans: { amount: 80, cadence: \\\"seasonal\\\", notes: \\\"Wait for sale\\\" },\\n    },\\n    hardExclusions: [\\\"leather\\\", \\\"leather\\\", \\\"dry clean only\\\"],\\n    perItemPriceCeiling: { amount: 150 },\\n    enabledRetailers: [\\\"Zalando\\\", \\\"ASOS\\\", \\\"Zalando\\\"],\\n  });\\n\\n  assert.equal(profile.country, \\\"LV\\\");\\n  assert.equal(profile.currency, \\\"EUR\\\");\\n  assert.deepEqual(Object.keys(profile.sizes), [\\\"tops\\\", \\\"shoes\\\"]);\\n  assert.equal(profile.budgetAnchors.jeans.currency, \\\"EUR\\\");\\n  assert.equal(profile.budgetAnchors.jeans.cadence, \\\"seasonal\\\");\\n  assert.equal(profile.budgetAnchors.jeans.notes, \\\"Wait for sale\\\");\\n  assert.deepEqual(profile.hardExclusions, [\\\"leather\\\", \\\"dry clean only\\\"]);\\n  assert.equal(profile.perItemPriceCeiling.currency, \\\"EUR\\\");\\n  assert.deepEqual(profile.enabledRetailers, [\\\"Zalando\\\", \\\"ASOS\\\"]);\\n});\\n\\ntest(\\\"persists profile data so it can be read by a later process\\\", async () => {\\n  const dir = await mkdtemp(join(tmpdir(), \\\"shopping-profile-\\\"));\\n  const path = join(dir, \\\"profile.json\\\");\\n\\n  try {\\n    await writeShoppingProfile(\\n      createDefaultShoppingProfile({\\n        country: \\\"DE\\\",\\n        currency: \\\"EUR\\\",\\n        perItemPriceCeiling: { amount: 200 },\\n        enabledRetailers: [\\\"About You\\\"],\\n      }),\\n      path,\\n    );\\n\\n    const reloaded = await readShoppingProfile(path);\\n\\n    assert.equal(reloaded.country, \\\"DE\\\");\\n    assert.equal(reloaded.perItemPriceCeiling.amount, 200);\\n    assert.deepEqual(reloaded.enabledRetailers, [\\\"About You\\\"]);\\n  } finally {\\n    await rm(dir, { recursive: true, force: true });\\n  }\\n});\\n\\ntest(\\\"updates fields programmatically while preserving existing records\\\", async () => {\\n  const dir = await mkdtemp(join(tmpdir(), \\\"shopping-profile-\\\"));\\n  const path = join(dir, \\\"profile.json\\\");\\n\\n  try {\\n    await writeShoppingProfile(\\n      createDefaultShoppingProfile({\\n        sizes: { tops: { value: \\\"L\\\" } },\\n        budgetAnchors: { coats: { amount: 180 } },\\n      }),\\n      path,\\n    );\\n\\n    const updated = await updateShoppingProfile(\\n      {\\n        sizes: { shoes: { value: \\\"43\\\", system: \\\"EU\\\" } },\\n        budgetAnchors: { shirts: { amount: 60 } },\\n        hardExclusions: [\\\"polyester\\\"],\\n      },\\n      path,\\n    );\\n\\n    assert.deepEqual(Object.keys(updated.sizes), [\\\"tops\\\", \\\"shoes\\\"]);\\n    assert.deepEqual(Object.keys(updated.budgetAnchors), [\\\"coats\\\", \\\"shirts\\\"]);\\n    assert.deepEqual(updated.hardExclusions, [\\\"polyester\\\"]);\\n  } finally {\\n    await rm(dir, { recursive: true, force: true });\\n  }\\n});\\n\\ntest(\\\"rejects invalid hard-constraint values\\\", () => {\\n  assert.throws(\\n    () => createDefaultShoppingProfile({ country: \\\"Latvia\\\" }),\\n    /country must be a 2-letter uppercase code/,\\n  );\\n  assert.throws(\\n    () => createDefaultShoppingProfile({ perItemPriceCeiling: { amount: -1 } }),\\n    /perItemPriceCeiling\\\\.amount must be a non-negative finite number/,\\n  );\\n});\\n\",\"exit_code\":0,\"status\":\"completed\"}}\nspec/KAN-6/runs/20260509T134122Z-25602553083/execution.json:23:{\"type\":\"item.completed\",\"item\":{\"id\":\"item_11\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,240p' README.md\\\"\",\"aggregated_output\":\"# The Dark Factory\\n\\nA self-driving Jira → GitHub Actions → Claude Code loop. A Jira ticket\\nbecomes either a reviewable pull request or a Jira-facing answer,\\nwithout anyone touching a terminal.\\n\\n## How it works\\n\\n1. Jira automation fires a `repository_dispatch` of type\\n   `jira_manual_button` carrying the issue key (a manual\\n   `workflow_dispatch` is also accepted).\\n2. [`.github/workflows/jira-dispatch.yml`](.github/workflows/jira-dispatch.yml)\\n   runs [`.github/scripts/jira-dispatch.mjs`](.github/scripts/jira-dispatch.mjs):\\n   fetches the ticket from Jira, prepares `spec/<TICKET-ID>/`, restores\\n   any cached Claude session, runs `anthropics/claude-code-base-action@main`\\n   on Opus, then commits, opens (or updates) the PR, and comments back\\n   on Jira.\\n3. Routing is by Jira label / type:\\n   - label `claude:answer` (or issue type `Question`) → answer mode.\\n     Claude writes only inside `spec/<TICKET-ID>/`; `response.md` is\\n     posted as a Jira comment.\\n   - label `claude:pr` (or default) → PR mode. Claude makes the\\n     repository changes on `tdf/<ticket-id>` and the workflow opens a\\n     PR.\\n4. When the PR merges,\\n   [`.github/workflows/jira-pr-merged.yml`](.github/workflows/jira-pr-merged.yml)\\n   transitions the Jira ticket to Done and deletes the head branch.\\n\\nSession continuity across runs comes from `actions/cache`-ing\\n`~/.claude/projects/` (key prefix `tdf-claude-<KEY>-`) plus replaying\\n`spec/<TICKET-ID>/state.json` and `transcript.md` so progress survives\\ncache eviction.\\n\\n## Per-ticket artefacts\\n\\n```\\nspec/<TICKET-ID>/\\n  spec.md         ticket snapshot (refreshed each run)\\n  plan.md         implementation plan (Claude owns this)\\n  response.md     Jira-facing summary or answer\\n  state.json      last_session_id, run_count, kind, conclusion\\n  transcript.md   one section per run\\n  runs/<ts>-<id>/ per-run prompt + execution copies\\n```\\n\\n## Repo layout\\n\\n| Path | Purpose |\\n|---|---|\\n| [`.github/workflows/`](.github/workflows) | The three live workflows (dispatch, PR-merged finalize, POC session). |\\n| [`.github/scripts/jira-dispatch.mjs`](.github/scripts/jira-dispatch.mjs) | Jira ↔ GitHub glue: ticket fetch, state, PR open/update, Jira comment, status transitions. |\\n| [`CLAUDE.md`](CLAUDE.md) | Operating contract for Claude when invoked by the dispatch flow. |\\n| [`docs/workflows.md`](docs/workflows.md) | High-level overview of the workflows with diagrams. |\\n| [`github_actions_claude_spec.md`](github_actions_claude_spec.md) | Authoritative spec for running Claude Code from GitHub Actions with cross-run session continuity. Includes validated POC and gotchas. |\\n| [`spec/<TICKET-ID>/`](spec) | Per-ticket artefacts (see above). |\\n| [`temp/`](temp) | POC artefacts (`temp/poc/`) and historical research (`temp/progress_plan.md`). Kept as history; not part of production. |\\n| [`two-pizzas.html`](two-pizzas.html) | Self-contained HTML deliverable from TDS-9. Open directly in a browser. |\\n\\n## Required GitHub secrets\\n\\n| Secret | Used for |\\n|---|---|\\n| `CLAUDE_CODE_OAUTH_TOKEN` | Auth for `anthropics/claude-code-base-action`. |\\n| `JIRA_BASE_URL`, `JIRA_EMAIL`, `JIRA_API_TOKEN` | Jira REST API for ticket fetch, comment, status transitions. |\\n| `GH_PR_TOKEN` | PAT with `contents: write` + `pull-requests: write` so the workflow can push to `tdf/*` branches and open PRs against branch-protected `main`. |\\n\\n## Triggering manually\\n\\nFrom a GitHub-side workflow run:\\n\\n```\\ngh workflow run jira-dispatch.yml 