export const SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE =
  "I found shopping intent, but I am not confident enough to make a proposal yet.";

const DEFAULT_MIN_PROPOSAL_CONFIDENCE = 0.7;

const GARMENT_CLASS_ALIASES = Object.freeze({
  accessories: ["accessory", "accessories", "bag", "belt", "cap", "hat", "scarf"],
  bottoms: [
    "bottom",
    "bottoms",
    "chino",
    "chinos",
    "jean",
    "jeans",
    "pant",
    "pants",
    "shorts",
    "trouser",
    "trousers",
  ],
  outerwear: ["coat", "jacket", "outerwear", "parka"],
  shoes: [
    "boot",
    "boots",
    "loafer",
    "loafers",
    "sandal",
    "sandals",
    "shoe",
    "shoes",
    "sneaker",
    "sneakers",
  ],
  tops: ["hoodie", "shirt", "shirts", "sweater", "t-shirt", "tee", "top", "tops"],
  underwear: ["boxer", "boxers", "brief", "briefs", "underwear"],
});

const SHOPPING_INTENT_TERMS = Object.freeze([
  "buy",
  "find",
  "get",
  "need",
  "order",
  "purchase",
  "shop",
  "shopping",
  "source",
  "want",
]);

export async function handleShoppingChatMessage({
  message,
  profile,
  searchTool,
  renderProposalCard,
  chat,
  minProposalConfidence = DEFAULT_MIN_PROPOSAL_CONFIDENCE,
} = {}) {
  const text = normalizeMessage(message);
  const shoppingIntent = detectShoppingIntent(text);

  if (!shoppingIntent.detected) {
    return {
      action: "none",
      reason: "no_shopping_intent",
      shoppingIntent,
    };
  }

  const garmentClass = extractGarmentClass(text);
  if (!garmentClass) {
    return askClarification(chat, {
      field: "garmentClass",
      message: "What kind of garment should I search for?",
      shoppingIntent,
    });
  }

  const size = extractExplicitSize(text) ?? resolveProfileSize(profile, garmentClass);
  if (!size) {
    return askClarification(chat, {
      field: "size",
      message: `What size should I use for ${garmentClass}?`,
      shoppingIntent,
      context: { garmentClass },
    });
  }

  const priceCeiling =
    extractPriceCeiling(text, profile) ?? resolveProfileBudget(profile, garmentClass);
  if (!priceCeiling) {
    return askClarification(chat, {
      field: "priceCeiling",
      message: `What is the maximum price per item for ${garmentClass}?`,
      shoppingIntent,
      context: { garmentClass, size },
    });
  }

  if (!searchTool || typeof searchTool.search !== "function") {
    throw new TypeError("searchTool.search must be a function.");
  }

  const searchContext = {
    garmentClass,
    originalMessage: text,
    priceCeiling,
    size,
  };
  const searchResult = await searchTool.search(searchContext);
  const confidence = normalizeConfidence(searchResult?.confidence);

  if (confidence < minProposalConfidence) {
    await publishPlainText(chat, SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE, {
      confidence,
      context: searchContext,
      reason: "low_confidence",
      searchResult,
    });
    return {
      action: "plain_text",
      confidence,
      context: searchContext,
      message: SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE,
      reason: "low_confidence",
      searchResult,
      shoppingIntent,
    };
  }

  if (!renderProposalCard || typeof renderProposalCard !== "function") {
    throw new TypeError("renderProposalCard must be a function.");
  }

  const proposalCard = await renderProposalCard(searchResult, searchContext);
  return {
    action: "proposal_card",
    confidence,
    context: searchContext,
    proposalCard,
    searchResult,
    shoppingIntent,
  };
}

export function detectShoppingIntent(message) {
  const text = normalizeMessage(message);
  const hasIntentTerm = SHOPPING_INTENT_TERMS.some((term) => hasWord(text, term));
  const garmentClass = extractGarmentClass(text);

  return {
    detected:
      Boolean(hasIntentTerm && garmentClass) ||
      Boolean(hasIntentTerm && looksLikeShoppingRequest(text)),
    garmentClass,
  };
}

export function extractGarmentClass(message) {
  const text = normalizeMessage(message);

  for (const [garmentClass, aliases] of Object.entries(GARMENT_CLASS_ALIASES)) {
    if (aliases.some((alias) => hasWord(text, alias))) {
      return garmentClass;
    }
  }

  return undefined;
}

export function extractExplicitSize(message) {
  const text = normalizeMessage(message);
  const labeled = text.match(/\b(?:size|sz)\s*[:#-]?\s*([a-z0-9][a-z0-9./-]{0,7})\b/i);
  if (labeled) {
    return { value: labeled[1].toUpperCase() };
  }

  const eu = text.match(/\b(?:eu|eur)\s*([0-9]{2}(?:\.[0-9])?)\b/i);
  if (eu) {
    return { system: "EU", value: eu[1] };
  }

  return undefined;
}

export function extractPriceCeiling(message, profile) {
  const text = normalizeMessage(message);
  const currency = normalizeCurrency(profile?.currency) ?? "EUR";
  const match = text.match(
    /(?:under|below|less than|max(?:imum)?|up to|<=?)\s*(eur|euro|euros|usd|dollars?|gbp|pounds?)?\s*([0-9]+(?:[.,][0-9]{1,2})?)\b/i,
  ) ?? text.match(
    /\b([0-9]+(?:[.,][0-9]{1,2})?)\s*(eur|euro|euros|usd|dollars?|gbp|pounds?)\b/i,
  );

  if (!match) {
    return undefined;
  }

  const amountIndex = Number.isFinite(Number.parseFloat(match[1])) ? 1 : 2;
  const symbol = amountIndex === 1 ? match[2] : match[1];
  const amount = Number.parseFloat(match[amountIndex].replace(",", "."));

  if (!Number.isFinite(amount) || amount < 0) {
    return undefined;
  }

  return {
    amount,
    currency: currencyFromToken(symbol) ?? currency,
  };
}

function resolveProfileSize(profile, garmentClass) {
  const size = profile?.sizes?.[garmentClass];
  if (!size?.value) {
    return undefined;
  }

  return {
    ...(size.system ? { system: size.system } : {}),
    value: String(size.value).trim(),
  };
}

function resolveProfileBudget(profile, garmentClass) {
  const anchor =
    profile?.budgetAnchors?.[garmentClass] ??
    profile?.budgetAnchors?.default ??
    profile?.perItemPriceCeiling;

  if (
    !anchor ||
    typeof anchor.amount !== "number" ||
    !Number.isFinite(anchor.amount) ||
    anchor.amount <= 0
  ) {
    return undefined;
  }

  return {
    amount: anchor.amount,
    currency: normalizeCurrency(anchor.currency) ?? normalizeCurrency(profile?.currency) ?? "EUR",
  };
}

async function askClarification(chat, result) {
  await publishPlainText(chat, result.message, result);
  return {
    action: "clarify",
    ...result,
  };
}

async function publishPlainText(chat, message, payload) {
  if (!chat) {
    return;
  }
  if (typeof chat.say === "function") {
    await chat.say(message, payload);
    return;
  }
  if (typeof chat === "function") {
    await chat(message, payload);
  }
}

function detectGarmentWord(text) {
  return Object.values(GARMENT_CLASS_ALIASES).some((aliases) =>
    aliases.some((alias) => hasWord(text, alias)),
  );
}

function looksLikeShoppingRequest(text) {
  return (
    /\b(wear|outfit|clothes|clothing|wardrobe|retailer|cart|something)\b/i.test(text) ||
    detectGarmentWord(text)
  );
}

function normalizeConfidence(value) {
  if (typeof value !== "number" || !Number.isFinite(value)) {
    return 0;
  }
  return Math.max(0, Math.min(1, value));
}

function normalizeCurrency(value) {
  if (typeof value !== "string") {
    return undefined;
  }
  const normalized = value.trim().toUpperCase();
  return /^[A-Z]{3}$/.test(normalized) ? normalized : undefined;
}

function currencyFromToken(token) {
  switch (token?.toLowerCase()) {
    case "eur":
    case "euro":
    case "euros":
      return "EUR";
    case "usd":
    case "dollar":
    case "dollars":
      return "USD";
    case "gbp":
    case "pound":
    case "pounds":
      return "GBP";
    default:
      return undefined;
  }
}

function hasWord(text, word) {
  return new RegExp(`\\b${escapeRegExp(word)}\\b`, "i").test(text);
}

function normalizeMessage(message) {
  if (typeof message !== "string" || !message.trim()) {
    throw new TypeError("message must be a non-empty string.");
  }
  return message.trim();
}

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

import { mkdir, readFile, writeFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

export const SHOPPING_PROFILE_SCHEMA_VERSION = 1;
export const DEFAULT_SHOPPING_PROFILE_PATH = "data/shopping-profile.json";

export function createDefaultShoppingProfile(overrides = {}) {
  return normalizeShoppingProfile({
    country: "LV",
    currency: "EUR",
    sizes: {},
    budgetAnchors: {},
    hardExclusions: [],
    perItemPriceCeiling: { amount: 0, currency: "EUR" },
    enabledRetailers: [],
    ...overrides,
  });
}

export async function readShoppingProfile(filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  try {
    const raw = await readFile(resolve(filePath), "utf8");
    return normalizeShoppingProfile(JSON.parse(raw));
  } catch (err) {
    if (err.code === "ENOENT") {
      return createDefaultShoppingProfile();
    }
    throw err;
  }
}

export async function writeShoppingProfile(profile, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  const normalized = normalizeShoppingProfile(profile);
  const target = resolve(filePath);
  await mkdir(dirname(target), { recursive: true });
  await writeFile(target, `${JSON.stringify(normalized, null, 2)}\n`, "utf8");
  return normalized;
}

export async function updateShoppingProfile(patch, filePath = DEFAULT_SHOPPING_PROFILE_PATH) {
  const current = await readShoppingProfile(filePath);
  const next = normalizeShoppingProfile({
    ...current,
    ...patch,
    sizes: patch.sizes ? { ...current.sizes, ...patch.sizes } : current.sizes,
    budgetAnchors: patch.budgetAnchors
      ? { ...current.budgetAnchors, ...patch.budgetAnchors }
      : current.budgetAnchors,
  });
  return writeShoppingProfile(next, filePath);
}

export function normalizeShoppingProfile(profile) {
  if (!profile || typeof profile !== "object" || Array.isArray(profile)) {
    throw new TypeError("Shopping profile must be an object.");
  }

  const country = normalizeCode(profile.country, "country", 2);
  const currency = normalizeCode(profile.currency, "currency", 3);
  const perItemPriceCeiling = normalizeMoney(
    profile.perItemPriceCeiling,
    "perItemPriceCeiling",
    currency,
  );

  return {
    schemaVersion: SHOPPING_PROFILE_SCHEMA_VERSION,
    country,
    currency,
    sizes: normalizeRecord(profile.sizes, "sizes", normalizeSize),
    budgetAnchors: normalizeRecord(profile.budgetAnchors, "budgetAnchors", (value, key) =>
      normalizeBudgetAnchor(value, key, currency),
    ),
    hardExclusions: normalizeUniqueStringArray(profile.hardExclusions, "hardExclusions"),
    perItemPriceCeiling,
    enabledRetailers: normalizeUniqueStringArray(profile.enabledRetailers, "enabledRetailers"),
  };
}

function normalizeCode(value, field, length) {
  if (typeof value !== "string") {
    throw new TypeError(`${field} must be a string.`);
  }
  const normalized = value.trim().toUpperCase();
  if (!new RegExp(`^[A-Z]{${length}}$`).test(normalized)) {
    throw new TypeError(`${field} must be a ${length}-letter uppercase code.`);
  }
  return normalized;
}

function normalizeRecord(value, field, normalizeValue) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`${field} must be an object.`);
  }

  return Object.fromEntries(
    Object.entries(value).map(([key, item]) => {
      const normalizedKey = String(key).trim();
      if (!normalizedKey) {
        throw new TypeError(`${field} keys must be non-empty strings.`);
      }
      return [normalizedKey, normalizeValue(item, normalizedKey)];
    }),
  );
}

function normalizeSize(value, key) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`sizes.${key} must be an object.`);
  }
  if (typeof value.value !== "string" || !value.value.trim()) {
    throw new TypeError(`sizes.${key}.value must be a non-empty string.`);
  }

  const normalized = { value: value.value.trim() };
  if (value.system !== undefined) {
    if (typeof value.system !== "string" || !value.system.trim()) {
      throw new TypeError(`sizes.${key}.system must be a non-empty string.`);
    }
    normalized.system = value.system.trim();
  }
  if (value.notes !== undefined) {
    if (typeof value.notes !== "string") {
      throw new TypeError(`sizes.${key}.notes must be a string.`);
    }
    normalized.notes = value.notes.trim();
  }
  return normalized;
}

function normalizeMoney(value, field, defaultCurrency) {
  if (!value || typeof value !== "object" || Array.isArray(value)) {
    throw new TypeError(`${field} must be an object.`);
  }
  if (typeof value.amount !== "number" || !Number.isFinite(value.amount) || value.amount < 0) {
    throw new TypeError(`${field}.amount must be a non-negative finite number.`);
  }

  return {
    amount: value.amount,
    currency:
      value.currency === undefined
        ? defaultCurrency
        : normalizeCode(value.currency, `${field}.currency`, 3),
  };
}

function normalizeBudgetAnchor(value, key, defaultCurrency) {
  const field = `budgetAnchors.${key}`;
  const normalized = normalizeMoney(value, field, defaultCurrency);

  if (value.cadence !== undefined) {
    if (!["per_item", "monthly", "seasonal", "annual"].includes(value.cadence)) {
      throw new TypeError(`${field}.cadence must be per_item, monthly, seasonal, or annual.`);
    }
    normalized.cadence = value.cadence;
  }
  if (value.notes !== undefined) {
    if (typeof value.notes !== "string") {
      throw new TypeError(`${field}.notes must be a string.`);
    }
    normalized.notes = value.notes.trim();
  }

  return normalized;
}

function normalizeUniqueStringArray(value, field) {
  if (!Array.isArray(value)) {
    throw new TypeError(`${field} must be an array.`);
  }

  return [...new Set(value.map((item) => {
    if (typeof item !== "string" || !item.trim()) {
      throw new TypeError(`${field} entries must be non-empty strings.`);
    }
    return item.trim();
  }))];
}

import test from "node:test";
import assert from "node:assert/strict";

import {
  SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE,
  detectShoppingIntent,
  handleShoppingChatMessage,
} from "../src/shopping-chat-flow.mjs";

test("detects shopping intent in a garment request", () => {
  assert.deepEqual(detectShoppingIntent("Find me black jeans under 100 euros"), {
    detected: true,
    garmentClass: "bottoms",
  });
});

test("asks for garment class before searching when the request is underspecified", async () => {
  const events = [];
  const result = await handleShoppingChatMessage({
    chat: {
      async say(message, payload) {
        events.push([message, payload.field]);
      },
    },
    message: "Please find something for work",
    searchTool: failSearchTool(),
  });

  assert.equal(result.action, "clarify");
  assert.equal(result.field, "garmentClass");
  assert.deepEqual(events, [["What kind of garment should I search for?", "garmentClass"]]);
});

test("asks for size before searching when neither text nor profile provides one", async () => {
  const result = await handleShoppingChatMessage({
    message: "Find a shirt under 80 euros",
    profile: { currency: "EUR", sizes: {}, budgetAnchors: {} },
    searchTool: failSearchTool(),
  });

  assert.equal(result.action, "clarify");
  assert.equal(result.field, "size");
  assert.equal(result.context.garmentClass, "tops");
});

test("asks for price ceiling when no explicit or profile budget is known", async () => {
  const result = await handleShoppingChatMessage({
    message: "Find shoes size 42",
    profile: {
      currency: "EUR",
      sizes: {},
      budgetAnchors: {},
      perItemPriceCeiling: { amount: 0, currency: "EUR" },
    },
    searchTool: failSearchTool(),
  });

  assert.equal(result.action, "clarify");
  assert.equal(result.field, "priceCeiling");
  assert.deepEqual(result.context.size, { value: "42" });
});

test("uses profile size and budget before dispatching search and rendering a proposal card", async () => {
  const searches = [];
  const cards = [];

  const result = await handleShoppingChatMessage({
    message: "Find a crisp shirt for the office",
    profile: {
      currency: "EUR",
      sizes: { tops: { value: "M", system: "International" } },
      budgetAnchors: { tops: { amount: 90, currency: "EUR", cadence: "per_item" } },
    },
    searchTool: {
      async search(context) {
        searches.push(context);
        return {
          confidence: 0.86,
          items: [{ id: "asket-shirt-1", title: "Oxford Shirt" }],
        };
      },
    },
    async renderProposalCard(searchResult, context) {
      cards.push([searchResult.items[0].id, context.garmentClass]);
      return { type: "proposal_card", itemId: searchResult.items[0].id };
    },
  });

  assert.equal(result.action, "proposal_card");
  assert.deepEqual(searches, [
    {
      garmentClass: "tops",
      originalMessage: "Find a crisp shirt for the office",
      priceCeiling: { amount: 90, currency: "EUR" },
      size: { system: "International", value: "M" },
    },
  ]);
  assert.deepEqual(cards, [["asket-shirt-1", "tops"]]);
  assert.deepEqual(result.proposalCard, { type: "proposal_card", itemId: "asket-shirt-1" });
});

test("does not render a proposal card for low-confidence search results", async () => {
  const events = [];
  let rendered = false;

  const result = await handleShoppingChatMessage({
    chat: async (message, payload) => {
      events.push([message, payload.reason]);
    },
    message: "Find shoes size EU 42 under EUR 120",
    searchTool: {
      async search() {
        return { confidence: 0.42, items: [{ id: "uncertain" }] };
      },
    },
    async renderProposalCard() {
      rendered = true;
    },
  });

  assert.equal(result.action, "plain_text");
  assert.equal(result.reason, "low_confidence");
  assert.equal(rendered, false);
  assert.deepEqual(events, [[SHOPPING_CHAT_LOW_CONFIDENCE_MESSAGE, "low_confidence"]]);
});

function failSearchTool() {
  return {
    async search() {
      throw new Error("search should not be called");
    },
  };
}

import { mkdtemp, rm } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  createDefaultShoppingProfile,
  readShoppingProfile,
  updateShoppingProfile,
  writeShoppingProfile,
} from "../src/shopping-profile.mjs";

test("creates a complete profile shape with required hard constraints", () => {
  const profile = createDefaultShoppingProfile({
    country: "lv",
    currency: "eur",
    sizes: {
      tops: { value: "M", system: "International" },
      shoes: { value: "42", system: "EU" },
    },
    budgetAnchors: {
      jeans: { amount: 80, cadence: "seasonal", notes: "Wait for sale" },
    },
    hardExclusions: ["leather", "leather", "dry clean only"],
    perItemPriceCeiling: { amount: 150 },
    enabledRetailers: ["Zalando", "ASOS", "Zalando"],
  });

  assert.equal(profile.country, "LV");
  assert.equal(profile.currency, "EUR");
  assert.deepEqual(Object.keys(profile.sizes), ["tops", "shoes"]);
  assert.equal(profile.budgetAnchors.jeans.currency, "EUR");
  assert.equal(profile.budgetAnchors.jeans.cadence, "seasonal");
  assert.equal(profile.budgetAnchors.jeans.notes, "Wait for sale");
  assert.deepEqual(profile.hardExclusions, ["leather", "dry clean only"]);
  assert.equal(profile.perItemPriceCeiling.currency, "EUR");
  assert.deepEqual(profile.enabledRetailers, ["Zalando", "ASOS"]);
});

test("persists profile data so it can be read by a later process", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-profile-"));
  const path = join(dir, "profile.json");

  try {
    await writeShoppingProfile(
      createDefaultShoppingProfile({
        country: "DE",
        currency: "EUR",
        perItemPriceCeiling: { amount: 200 },
        enabledRetailers: ["About You"],
      }),
      path,
    );

    const reloaded = await readShoppingProfile(path);

    assert.equal(reloaded.country, "DE");
    assert.equal(reloaded.perItemPriceCeiling.amount, 200);
    assert.deepEqual(reloaded.enabledRetailers, ["About You"]);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("updates fields programmatically while preserving existing records", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-profile-"));
  const path = join(dir, "profile.json");

  try {
    await writeShoppingProfile(
      createDefaultShoppingProfile({
        sizes: { tops: { value: "L" } },
        budgetAnchors: { coats: { amount: 180 } },
      }),
      path,
    );

    const updated = await updateShoppingProfile(
      {
        sizes: { shoes: { value: "43", system: "EU" } },
        budgetAnchors: { shirts: { amount: 60 } },
        hardExclusions: ["polyester"],
      },
      path,
    );

    assert.deepEqual(Object.keys(updated.sizes), ["tops", "shoes"]);
    assert.deepEqual(Object.keys(updated.budgetAnchors), ["coats", "shirts"]);
    assert.deepEqual(updated.hardExclusions, ["polyester"]);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("rejects invalid hard-constraint values", () => {
  assert.throws(
    () => createDefaultShoppingProfile({ country: "Latvia" }),
    /country must be a 2-letter uppercase code/,
  );
  assert.throws(
    () => createDefaultShoppingProfile({ perItemPriceCeiling: { amount: -1 } }),
    /perItemPriceCeiling\.amount must be a non-negative finite number/,
  );
});

